"""PreparePhase — 세션 초기화, 도구 수집, Provider 활성화."""

from __future__ import annotations

import logging

from mantis.executor.protocol import ExecutionContext
from mantis.executor.phases.protocol import PhaseResult

logger = logging.getLogger(__name__)


class DefaultPrepare:
    """기본 PreparePhase.

    1. 세션 복구 (state가 있으면)
    2. on_start 미들웨어
    3. 유저 메시지 추가
    """

    name = "prepare"

    async def run(self, ctx: ExecutionContext) -> PhaseResult:
        # 세션 복구
        if ctx.state is not None:
            try:
                saved = await ctx.state.load(ctx.session_id)
                if saved:
                    logger.info("세션 '%s' 복구됨", ctx.session_id)
            except Exception as e:
                logger.warning("세션 복구 실패: %s", e)

        # 미들웨어 on_start
        for mw in ctx.middlewares:
            await mw.on_start(ctx.run_ctx)

        # 유저 메시지 추가
        ctx.conversation.add_user(ctx.run_ctx.last_user_message)

        return PhaseResult(status="continue")
